<?php

namespace App\Services;

use OpenAI\Laravel\Facades\OpenAI;

/**
 * PressReleaseAgent
 * A service for using the power of AI to generate "press releases" for the Contest.
 * Generated by ChatGPT, refined by me.
 *
 * @package App\Services
 */
class PressReleaseAgent
{
    /* Example usage:

    $agent = app(PressReleaseAgent::class);

    $press = $agent->spotlight([
        'title' => 'Magenta Men',
        'description' => 'A funk-based duo inspired by Prince and Morris Day',
        'highlights' => [
            'Dual male leads',
            'Retro-funk aesthetic',
            'High-energy performances',
        ],
        'cta' => 'Vote now on the official contest platform',
    ]);

    return response()->json($press);
    */

    protected string $model = 'gpt-4.1-mini';

    public function __construct()
    {
        $this->model = config('contest.ai.model', 'gpt-4.1-mini');
    }

    protected function systemPrompt(): string
    {
        return <<<PROMPT
You are a professional press officer for Song Contest by CATAWOL Records.

Your role is to write compelling, polished press releases based on structured input.

General rules:
- Always include a strong, attention-grabbing headline
- Open with a clear summary (who, what, why it matters)
- Match tone to the press release type
- Use vivid but controlled language (avoid fluff)
- Include quotes when provided or generate one if missing
- End with a clear call to action

Press release types and styles:

Contest Announcement:
- Big, exciting, promotional
- Focus on scale and participation

Results Announcement:
- Dramatic and celebratory
- Emphasise winners and impact

Artist Feature:
- Personal and narrative
- Explore background and artistic identity

Event Promotion:
- Urgent and time-sensitive
- Focus on attendance

Return JSON with:
- title
- body
- cta
The body should be in Markdown format, using level 2 headings.
PROMPT;
    }

    protected function run(array $payload): array
    {
        $response = OpenAI::chat()->create([
            'model'           => $this->model,
            'temperature'     => 0.7,
            'response_format' => ['type' => 'json_object'],
            'messages'        => [
                [
                    'role'    => 'system',
                    'content' => $this->systemPrompt(),
                ],
                [
                    'role' => 'user',
                    'content' => "Generate a press release using this data:\n\n" . json_encode($payload, JSON_PRETTY_PRINT),
                ],
            ],
        ]);

        return json_decode(
            $response->choices[0]->message->content,
            true
        );
    }

    // Different types of press releases...

    public function contestAnnouncement(array $data): array
    {
        return $this->run([
            'type' => 'Contest Announcement',
            ...$data,
        ]);
    }

    public function results(array $data): array
    {
        return $this->run([
            'type' => 'Results Announcement',
            ...$data,
        ]);
    }

    public function artistFeature(array $data): array
    {
        return $this->run([
            'type' => 'Artist Feature',
            ...$data,
        ]);
    }

    public function eventPromotion(array $data): array
    {
        return $this->run([
            'type' => 'Event Promotion',
            ...$data,
        ]);
    }
}
